def check(C1, C2):
    MAX = 255
    res = []
    for X in range(256):
        ov = X * C1 > MAX
        v = (X * C1) & MAX
        if ov or v > C2:
            res.append(X)

    # expected
    X_max = MAX // C1
    if X_max * C1 > C2:
        ans = list(range(X_max, 256))
    else:
        ans = list(range(X_max + 1, 256))
    if res != ans:
        print(f"FAILED C1={C1} C2={C2}")
        print(res, ans)
    return res == ans

for C1 in range(2, 256):
    for C2 in range(256 - C1 + 1, 256):
        if not check(C1, C2):
            print("ERROR")
            exit(1)
print("ALL OK")
EOF
